SELECT MAX(trend_value)
FROM financial_trends
WHERE trend_type = 'increasing savings';

SELECT AVG(score) AS average_score, COUNT(*) AS number_of_records
FROM financial_scores
WHERE date < '2023-06-02';

SELECT individual_id, AVG(score) AS average_score
FROM financial_scores
GROUP BY individual_id;

SELECT individual_id, trend_type, trend_value, trend_date
FROM financial_trends
WHERE trend_type = 'increasing savings';

SELECT individual_id, SUM(amount) as total_savings
FROM savings
GROUP BY individual_id;

SELECT phone_number
FROM phone_communications
WHERE call_duration >= 45;

SELECT individual_id, SUM(amount) AS total_savings
FROM savings
GROUP BY individual_id;
